        "安家": "安全感落地，開始談未來"
      };
      return _.get(map, stage, "等待變量初始化");
    }

    function renderMeter(selector, value) {
      const safe = clampPercent(value);
      $(`${selector} .sr-value`).text(String(safe));
      $(`${selector} .sr-fill`).css("width", `${safe}%`);
    }

