      $("#sr-stage").text(stage);
      $("#sr-stage-line").text(stageText(stage));
      $("#sr-live").attr("data-live", String(live));
      $("#sr-live .sr-live-text").text(live ? "裏帳直播中" : "待命");

      renderMeter("#sr-possess", possess);
      renderMeter("#sr-safety", safety);
      renderMeter("#sr-intimacy", intimacy);
    }

