import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  stat_data: z.object({
    石睿: z
      .object({
        佔有慾: z.coerce.number().transform(v => _.clamp(v, 1, 100)),
        安全感: z.coerce.number().transform(v => _.clamp(v, 1, 100)),
        親密度: z.coerce.number().transform(v => _.clamp(v, 1, 100)),
        $cd: z.coerce.number().transform(v => _.clamp(v, 0, 3)),
        _階段: z.enum(['蟄伏', '試爪', '圈地', '築巢', '安家']),
        直播中: z.boolean(),
      })
      .transform(data => {
        if (data.安全感 >= 70 && data.親密度 >= 60) {
          data._階段 = '安家';
        } else if ((data.佔有慾 >= 60 || data.親密度 >= 60) && data.安全感 < 70) {
          data._階段 = '築巢';
        } else if (data.佔有慾 >= 45 && data.安全感 < 50) {
          data._階段 = '圈地';
        } else if (data.佔有慾 >= 25 || data.安全感 >= 25 || data.親密度 >= 25) {
          data._階段 = '試爪';
        } else {
          data._階段 = '蟄伏';
        }
        return data;
      }),
  }),
});

$(() => {
  registerMvuSchema(Schema);
})

(async () => {
  await waitGlobalInitialized('Mvu');

  const characterPath = 'stat_data.石睿';
  const cdPath = `${characterPath}.$cd`;
  const stagePath = `${characterPath}._階段`;
  const coreVariables = [
    { path: `${characterPath}.佔有慾`, min: 1, max: 100, minDelta: 0, maxDelta: 2 },
    { path: `${characterPath}.安全感`, min: 1, max: 100, minDelta: -2, maxDelta: 2 },
    { path: `${characterPath}.親密度`, min: 1, max: 100, minDelta: -2, maxDelta: 2 },
  ];

  function toNumber(value, fallback) {
    const numberValue = Number(value);
    return Number.isFinite(numberValue) ? numberValue : fallback;
  }

  function normalizeNumber(value, fallback, min, max) {
    return _.clamp(toNumber(value, fallback), min, max);
  }

  function computeStage(data) {
    const possessiveness = normalizeNumber(_.get(data, `${characterPath}.佔有慾`), 1, 1, 100);
    const safety = normalizeNumber(_.get(data, `${characterPath}.安全感`), 1, 1, 100);
    const intimacy = normalizeNumber(_.get(data, `${characterPath}.親密度`), 1, 1, 100);

    if (safety >= 70 && intimacy >= 60) return '安家';
    if ((possessiveness >= 60 || intimacy >= 60) && safety < 70) return '築巢';
    if (possessiveness >= 45 && safety < 50) return '圈地';
    if (possessiveness >= 25 || safety >= 25 || intimacy >= 25) return '試爪';
    return '蟄伏';
  }

  eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, (newVariables, oldVariables) => {
    const oldCd = normalizeNumber(_.get(oldVariables, cdPath), 0, 0, 3);

    if (oldCd > 0) {
      for (const variable of coreVariables) {
        const oldValue = normalizeNumber(_.get(oldVariables, variable.path), 1, variable.min, variable.max);
        _.set(newVariables, variable.path, oldValue);
      }
      _.set(newVariables, cdPath, oldCd - 1);
      _.set(newVariables, stagePath, computeStage(newVariables));
      return;
    }

    let changed = false;
    for (const variable of coreVariables) {
      const oldValue = normalizeNumber(_.get(oldVariables, variable.path), 1, variable.min, variable.max);
      const requestedValue = normalizeNumber(_.get(newVariables, variable.path), oldValue, variable.min, variable.max);
      const limitedValue = _.clamp(
        requestedValue,
        oldValue + variable.minDelta,
        oldValue + variable.maxDelta,
      );

      if (limitedValue !== oldValue) changed = true;
      _.set(newVariables, variable.path, limitedValue);
    }

    _.set(newVariables, cdPath, changed ? 3 : 0);
    _.set(newVariables, stagePath, computeStage(newVariables));
  });
})();
